// ============================================================
// בדיקת מפתח API + חילוץ נתוני המיקום
// ============================================================
const apiKey = $input.first().json.headers['x-api-key'];
const SECRET_KEY = 'YOUR_SECRET_API_KEY'; // <-- אותו מפתח כמו ב-workflow הראשון

if (apiKey !== SECRET_KEY) {
  return [{
    json: {
      __authorized: false,
      error: 'Unauthorized'
    }
  }];
}

const body = $input.first().json.body;

// נתוני המיקום שנשלחים מהאפליקציה
const locationData = {
  timestamp:    body.timestamp   ?? new Date().toISOString(),
  driver:       body.driver      ?? 'לא ידוע',
  route:        body.route       ?? 'לא ידוע',
  lat:          body.lat         ?? null,
  lon:          body.lon         ?? null,
  station:      body.station     ?? null,
  stationIndex: body.stationIndex ?? -1,

  // שדות נוספים לנוחות הגיליון
  date: new Date(body.timestamp ?? Date.now()).toLocaleDateString('he-IL'),
  time: new Date(body.timestamp ?? Date.now()).toLocaleTimeString('he-IL'),
  googleMapsLink: (body.lat && body.lon)
    ? `https://maps.google.com/?q=${body.lat},${body.lon}`
    : ''
};

return [{ json: { __authorized: true, ...locationData } }];

// ============================================================
// לוגיקת סיום נסיעה אוטומטי
// ============================================================
// האפליקציה שולחת stationIndex = מספר התחנה הנוכחית (מ-0)
// אם הגיע לתחנה האחרונה — שלח פקודת terminate
//
// עדכן את TOTAL_STATIONS לפי מסלול אם צריך
// או בדוק לפי שם התחנה

const data = $input.first().json;

// -------------------------------------------------------
// אפשרות א: סיום לפי מספר תחנה
// הגדר כאן כמה תחנות יש בכל מסלול
// -------------------------------------------------------
const stationsPerRoute = {
  'מסלול צפון — בוקר':   5,
  'מסלול דרום — צהריים': 4,
  'מסלול מזרח — ערב':    4,
};

const totalStations = stationsPerRoute[data.route] ?? 999;
const isLastStation = data.stationIndex >= totalStations - 1;

// -------------------------------------------------------
// אפשרות ב: סיום לפי שם תחנה (בטל הערה אם מעדיף)
// -------------------------------------------------------
// const isLastStation = data.station === 'קצה המסלול';

return [{
  json: {
    ...data,
    terminate: isLastStation,
    reason: isLastStation ? 'הגעת לתחנה הסופית' : null
  }
}];
